        "size": "size5",
        "color": "color1"
      },
      "theme": "primary",
      "padding": "type2",
      "gapSize": "m",
      "text": {
        "size": "size2",
        "align": "left",
        "color": "color1",
        "items": [
          {
            "type": "text",
            "content": "100 % хлопок — мягкая, дышащая, не просвечивает. "
