        "color": "color1"
      },
      "theme": "primary",
      "padding": "type2",
      "gapSize": "m",
      "text": {
        "size": "size2",
        "align": "left",
        "color": "color1",
        "items": [
          {
            "type": "text",
            "content": "Футболка легко сочетается с джинсами, шортами или худи. Плотная и при этом лёгкая ткань, аккуратные швы, идеально для фанатов аниме и streetwear‑образов."
          }
        ]
      }
    },
    {
      "widgetName": "raTextBlock",
      "title": {
        "items": [
          {
            "type": "text",
            "content": "Уход за изделием"
          }
