        "size": "size5",
        "color": "color1"
      },
      "theme": "primary",
      "padding": "type2",
      "gapSize": "m",
      "text": {
        "size": "size2",
        "align": "left",
        "color": "color1",
        "items": [
          {
            "type": "text",
            "content": "Стирать при 30 °C наизнанку без отбеливателя; гладить с изнанки при ≤110 °C; принт и вышивка сохранят яркость более 40 стирок."
          }
        ]
      }
    },
    {
      "widgetName": "raTextBlock",
      "title": {
        "items": [
          {
            "type": "text",
            "content": "Часто задаваемые вопросы"
          }
